#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=35010,K=110,INF=0x3f3f3f3f;int a[N],b[N],dp[N][K],tag[N<<2],Mn[N<<2],pre[N],c[N];
inline void update(int cur){Mn[cur]=min(Mn[cur<<1],Mn[cur<<1|1]);}
inline void pushdown(int cur){int &x=tag[cur];tag[cur<<1]+=x;Mn[cur<<1]+=x;tag[cur<<1|1]+=x;Mn[cur<<1|1]+=x;x=0;}
void build(int l,int r,int cur,int j)
{
//	printf("%d %d\n",l,r);
	if(l==r){Mn[cur]=dp[l][j];return;}int mid=(l+r)>>1;
	build(l,mid,cur<<1,j);build(mid+1,r,cur<<1|1,j);update(cur);
}
void Add(int l,int r,int ql,int qr,int cur,int val)
{
//	printf("%d %d\n",l,r);
	if(ql<=l&&r<=qr){tag[cur]+=val;Mn[cur]+=val;return;}pushdown(cur);int mid=(l+r)>>1;
	if(ql<=mid)Add(l,mid,ql,qr,cur<<1,val);if(qr>mid)Add(mid+1,r,ql,qr,cur<<1|1,val);update(cur);
}
int Qry(int l,int r,int ql,int qr,int cur)
{
//	printf("%d %d %d %d %d\n",l,r,ql,qr,cur);;
	int mi=INF;if(ql<=l&&r<=qr)return Mn[cur];pushdown(cur);int mid=(l+r)>>1;
	if(ql<=mid)mi=min(mi,Qry(l,mid,ql,qr,cur<<1));if(qr>mid)mi=min(mi,Qry(mid+1,r,ql,qr,cur<<1|1));update(cur);return mi;
}
int main()
{
	int n=read(),k=read();rep(1,n,i)a[i]=read();rep(1,n,i)pre[i]=b[a[i]],b[a[i]]=i;
//	rep(1,n,i)printf("%d ",pre[i]);puts("");
	memset(dp,0x3f,sizeof(dp));dp[0][1]=0;
	rep(1,n,i){dp[i][1]=dp[i-1][1]+(pre[i]?(i-pre[i]):0);}
	
	rep(2,k,j)
	{
		memset(tag,0,sizeof(tag));memset(Mn,0,sizeof(Mn));
		build(1,n,1,j-1);rep(j,n,i)
		{
			
			if(pre[i]-1>=1)Add(1,n,1,pre[i]-1,1,i-pre[i]);
			dp[i][j]=Qry(1,n,1,i-1,1);
		}
	}
//	rep(1,n,i){rep(1,k,j)printf("%d ",dp[i][j]>10000?-1:dp[i][j]);puts("g");}
	printf("%d",dp[n][k]);return 0;
}
